// bulkDeleteReport is the per-run summary written to stdout and used to
// drive an agent's continuation logic. The progress file makes the run
// resumable; if a process is killed mid-loop, a follow-up invocation skips
// ids already marked done rather than re-deleting them.
type bulkDeleteReport struct {
	Matched            int             `json:"matched"`
	Deleted            int             `json:"deleted"`
	SkippedAlreadyDone int             `json:"skipped_already_done"`
	Errors             []bulkDeleteErr `json:"errors"`
	ProgressFile       string          `json:"progress_file,omitempty"`
	IDs                []string        `json:"ids,omitempty"`
	Truncated          bool            `json:"truncated,omitempty"`
	DryRun             bool            `json:"dry_run,omitempty"`
	VerifySkipped      bool            `json:"verify_skipped,omitempty"`
	DogfoodSkipped     bool            `json:"dogfood_skipped,omitempty"`
}

type bulkDeleteErr struct {
	ID  string `json:"id"`
	Err string `json:"err"`
}

// dryRunIDPreview bounds the matched-id slice we render in --dry-run mode
// so a half-million-row predicate doesn't produce an unreadable preview.
const dryRunIDPreview = 100

// bulkDeleteProgress is the on-disk schema for the resume file. We write
// the full set of deleted ids rather than a counter so a partial run can
// be resumed even if the source predicate's match-set has changed between
// invocations.
type bulkDeleteProgress struct {
	ListID  string   `json:"list_id"`
	Where   string   `json:"where"`
	Deleted []string `json:"deleted"`
	Updated string   `json:"updated"`
}

func progressFilePath(listID string) string {
	home, _ := os.UserHomeDir()
	return filepath.Join(home, ".local", "share", "emailoctopus-pp-cli", fmt.Sprintf("bulk-delete.%s.progress.json", listID))
}

func loadProgress(path string) (map[string]struct{}, *bulkDeleteProgress, error) {
	done := map[string]struct{}{}
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return done, &bulkDeleteProgress{}, nil
		}
		return nil, nil, err
	}
	var p bulkDeleteProgress
	if err := json.Unmarshal(data, &p); err != nil {
		return done, &bulkDeleteProgress{}, nil
	}
	for _, id := range p.Deleted {
		done[id] = struct{}{}
	}
	return done, &p, nil
}

func saveProgress(path string, p *bulkDeleteProgress) error {
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	p.Updated = time.Now().UTC().Format(time.RFC3339)
	body, err := json.MarshalIndent(p, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, body, 0o644)
}

// resolveBulkDeleteIDs runs the predicate against the local contacts table
// and returns the matched id set. The predicate vocabulary is intentionally
// narrow (status=, tag:, email-domain=) so a user can't accidentally type
// SQL that runs over the whole resources table.
func resolveBulkDeleteIDs(db *store.Store, listID, where string) ([]string, error) {
	clauses, binds, err := parseBulkDeleteWhere(where)
	if err != nil {
		return nil, err
	}
	binds = append([]any{listID}, binds...)
	query := `SELECT id FROM contacts WHERE lists_id = ? AND ` + strings.Join(clauses, " AND ") + ` ORDER BY id`
	rows, err := db.Query(query, binds...)
	if err != nil {
		return nil, fmt.Errorf("running predicate: %w", err)
	}
	defer rows.Close()
	var ids []string
	for rows.Next() {
		var id sql.NullString
		if err := rows.Scan(&id); err != nil {
			return nil, err
		}
		if id.Valid {
			ids = append(ids, id.String)
		}
	}
	return ids, rows.Err()
}

// parseBulkDeleteWhere turns "status=unsubscribed AND tag:churned" into a
// (sqlClauses, binds) pair. Only the documented operators are recognized;
// anything else returns a usageErr so the user sees a clear "unknown
// predicate" message rather than a SQL syntax error.
func parseBulkDeleteWhere(where string) ([]string, []any, error) {
	parts := strings.Split(where, " AND ")
	var clauses []string
	var binds []any
	for _, raw := range parts {
		p := strings.TrimSpace(raw)
		if p == "" {
			continue
		}
		switch {
		case strings.HasPrefix(p, "status="):
			v := strings.TrimPrefix(p, "status=")
			clauses = append(clauses, "json_extract(data,'$.status') = ?")
			binds = append(binds, v)
		case strings.HasPrefix(p, "tag:"):
			v := strings.TrimPrefix(p, "tag:")
			clauses = append(clauses, "EXISTS (SELECT 1 FROM json_each(json_extract(data,'$.tags')) WHERE value = ?)")
			binds = append(binds, v)
		case strings.HasPrefix(p, "email-domain="):
			v := strings.TrimPrefix(p, "email-domain=")
			// PATCH bulk-delete-like-escape-and-nil-deref: escape SQL LIKE
			// metacharacters from user-supplied domain (Greptile P1). A
			// value like `exa%le.com` would otherwise widen the deletion
			// set to every contact whose email contains `exa…le.com` as
			// a substring. The bound parameter still uses `%@` as the
			// leading wildcard for the local-part; only the domain
			// portion is escaped, with `ESCAPE '\'` selecting the escape
			// character SQLite uses for the metacharacters.
			escaped := strings.NewReplacer(`\`, `\\`, `%`, `\%`, `_`, `\_`).Replace(strings.ToLower(v))
			clauses = append(clauses, `LOWER(json_extract(data,'$.email_address')) LIKE ? ESCAPE '\'`)
			binds = append(binds, "%@"+escaped)
		default:
			return nil, nil, fmt.Errorf("unknown predicate %q (supported: status=<value>, tag:<value>, email-domain=<value>, joined with AND)", p)
		}
	}
	if len(clauses) == 0 {
		return nil, nil, fmt.Errorf("--where parsed to no clauses; specify at least one (e.g. status=unsubscribed)")
	}
	return clauses, binds, nil
}

func newContactsBulkDeleteCmd(flags *rootFlags) *cobra.Command {
	var listID string
	var where string
	var rate float64

	cmd := &cobra.Command{
		Use:   "bulk-delete",
		Short: "Delete contacts matching a local predicate (paced, resumable)",
		Example: `  # Preview matches before deleting (always start here)
  emailoctopus-pp-cli contacts bulk-delete --list c81c21ca-51cc-11f1-ad3e-ffeba75576ac --where status=unsubscribed --dry-run

  # Delete all unsubscribed contacts from a list
  emailoctopus-pp-cli contacts bulk-delete --list c81c21ca-51cc-11f1-ad3e-ffeba75576ac --where status=unsubscribed

  # Combine predicates with AND
  emailoctopus-pp-cli contacts bulk-delete --list c81c21ca-51cc-11f1-ad3e-ffeba75576ac --where "status=unsubscribed AND tag:churned" --rate 5`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if listID == "" {
				return usageErr(fmt.Errorf("--list is required"))
			}
			if where == "" {
				return usageErr(fmt.Errorf("--where is required (e.g. status=unsubscribed, tag:churned, email-domain=example.com)"))
			}

			dbPath := defaultDBPath("emailoctopus-pp-cli")
			db, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w\nRun 'emailoctopus-pp-cli sync' first.", err)
			}
			defer db.Close()

			ids, err := resolveBulkDeleteIDs(db, listID, where)
			if err != nil {
				return usageErr(err)
			}
			report := bulkDeleteReport{Matched: len(ids)}

			progressPath := progressFilePath(listID)
			done, progress, loadErr := loadProgress(progressPath)
			if loadErr != nil {
				// Non-ENOENT errors (permission denied, corrupt directory)
				// surface here; loadProgress returns a nil progress on
				// those, which would panic on the field assignment below.
				return fmt.Errorf("reading progress file %s: %w (delete the file to start fresh)", progressPath, loadErr)
			}
			progress.ListID = listID
			progress.Where = where

			pending := make([]string, 0, len(ids))
			for _, id := range ids {
				if _, ok := done[id]; ok {
					report.SkippedAlreadyDone++
					continue
				}
				pending = append(pending, id)
			}

			if flags.dryRun {
				report.DryRun = true
				if len(pending) > dryRunIDPreview {
					report.IDs = append([]string{}, pending[:dryRunIDPreview]...)
					report.Truncated = true
				} else {
					report.IDs = pending
				}
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}
			if cliutil.IsVerifyEnv() {
				report.VerifySkipped = true
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}
			if cliutil.IsDogfoodEnv() {
				report.DogfoodSkipped = true
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}

			sleep := time.Duration(0)
			if rate > 0 {
				sleep = time.Duration(float64(time.Second) / rate)
			}

			for i, id := range pending {
				path := "/lists/" + listID + "/contacts/" + id
				_, status, derr := c.Delete(path)
				if derr != nil && status != 404 {
					report.Errors = append(report.Errors, bulkDeleteErr{ID: id, Err: derr.Error()})
				} else {
					report.Deleted++
					progress.Deleted = append(progress.Deleted, id)
					if perr := saveProgress(progressPath, progress); perr != nil {
						fmt.Fprintf(os.Stderr, "warning: progress write failed: %v\n", perr)
					}
				}
				if (i+1)%10 == 0 {
					fmt.Fprintf(os.Stderr, "Deleted %d/%d…\n", report.Deleted, len(pending))
				}
				if i < len(pending)-1 && sleep > 0 {
					time.Sleep(sleep)
				}
			}
			report.ProgressFile = progressPath
			return printJSONFiltered(cmd.OutOrStdout(), report, flags)
		},
	}

	cmd.Flags().StringVar(&listID, "list", "", "List id (required)")
	cmd.Flags().StringVar(&where, "where", "", "Predicate: status=<v>, tag:<v>, email-domain=<v>, joined with AND")
	cmd.Flags().Float64Var(&rate, "rate", 8, "Max delete requests per second")
	return cmd
}
